body:
Hi, Show you my testcase directly.

```verilog
// demo.v
module t (
    input   logic   clk,
    output  logic   en_pp
);
    sub U_SUB (
        .clk        (clk),
        .en         (1'b1),
        .en_pp      (en_pp)
    );
endmodule

module sub (
    input   logic   clk,
    input   logic   en,
    output  logic   en_pp
);
logic pp[1:0];
always @ (*) begin
    pp[0] = en;
    en_pp = pp[1]; // This assignment statement does not take effect.
end
always @ (posedge clk) begin
    pp[1] <= pp[0];
    $display("en_pp: %d", en_pp);
end
endmodule
```
```cpp
// sim_main.cpp
#include "Vdemo.h"
#include "verilated.h"

vluint64_t main_time = 0;
double sc_time_stamp() { return main_time; }

int main(int argc, char** argv, char** env) {
    Verilated::commandArgs(argc, argv);
    Vdemo* top = new Vdemo;
    while (!Verilated::gotFinish() && main_time < 40) {
        top->eval();
        main_time++;
        top->clk = !top->clk;
   }
    delete top;
    exit(0);
}
```
0 error or warning when translating and running the case.
